import { createSlice } from '@reduxjs/toolkit';


let initialState = {
	sidebar:{
		department:false,
		category:false,
		categoryArray : [
			{
				menswear:{
					top:false,
					bottoms:false,
					outerwear:false,
					footwear:false,
					tailoring:false,
					accessories:false,

				},
			},
			{
				womenswear:{
					top:false,
					bottoms:false,
					outerwear:false,
					footwear:false,
					dresses:false,
					accessories:false,
					bagsAndLugguage:false
				}
			}
		],
		size:false,
		designer:false,
		price:false,
		condition:false
	},
	listing:{
		listing:[]
	}
}

const shopSlice = createSlice({
	name:'shop',
	initialState,
	reducers:{
		openDepartment:state => {
			state.sidebar.department = !state.sidebar.department
		},
		openCategory:state => {
			state.sidebar.category = !state.sidebar.category
		},
		openSize:state => {
			state.sidebar.size = !state.sidebar.size
		},
		openDesigner:state => {
			state.sidebar.designer = !state.sidebar.designer
		},
		openPrice:state => {
			state.sidebar.price = !state.sidebar.price
		},
		openCondition:state => {
			state.sidebar.condition = !state.sidebar.condition
		},
		getListing:(state, action) => {
			state.listing.listing = action.payload
		}

	}
})

export const {
	openDepartment,
	openCategory,
	openSize,
	openDesigner,
	openPrice,
	openCondition,
	getListing
} = shopSlice.actions
export const shopSelector = state => state.shop
export default shopSlice.reducer
